{"code": "import json
import re

# Load latest packages
package_file = locals()['var_functions.query_db:28']
if isinstance(package_file, str) and package_file.endswith('.json'):
    with open(package_file, 'r') as f:
        npm_packages = json.load(f)
else:
    npm_packages = package_file

# Find latest version for each package
latest_packages = {}
for pkg in npm_packages:
    name = pkg['Name']
    ordinal = int(pkg['Ordinal'])
    if name not in latest_packages or ordinal > latest_packages[name]['ordinal']:
        latest_packages[name] = {
            'name': name,
            'version': pkg['Version'],
            'ordinal': ordinal,
            'system': pkg['System']
        }

latest_list = list(latest_packages.values())

# Load package-project mappings
mapping_file = locals()['var_functions.query_db:32']
if isinstance(mapping_file, str) and mapping_file.endswith('.json'):
    with open(mapping_file, 'r') as f:
        mappings = json.load(f)
else:
    mappings = mapping_file

# Create mapping dict: package -> project_name
package_to_project = {}
for m in mappings:
    package_to_project[m['Name']] = m['ProjectName']

# Load project info and extract stars
project_file = locals()['var_functions.query_db:36']
if isinstance(project_file, str) and project_file.endswith('.json'):
    with open(project_file, 'r') as f:
        project_infos = json.load(f)
else:
    project_infos = project_file

# Create project stats dict
project_stats = {}
for proj in project_infos:
    info = proj['Project_Information']

    # Extract project name and stars using regex
    # Format: "The project {owner/repo} on GitHub ... {stars} stars ..."
    match = re.search(r'project\s+([\w\-]+/[\w\-]+)\s+.*?\b(\d+)\s+stars\b', info)
    if match:
        project_name = match.group(1)
        stars = int(match.group(2))
        project_stats[project_name] = stars

print(f'Total project stats: {len(project_stats)}')
print('Sample:')
for k, v in list(project_stats.items())[:5]:
    print(f'  {k}: {v} stars')

# Match packages with their stars
package_stars = []
for pkg in latest_list:
    project_name = package_to_project.get(pkg['name'])
    if project_name:
        stars = project_stats.get(project_name, 0)
        if stars > 0:
            package_stars.append({
                'name': pkg['name'],
                'version': pkg['version'],
                'project_name': project_name,
                'stars': stars
            })

# Sort by stars and get top 5
top_packages = sorted(package_stars, key=lambda x: x['stars'], reverse=True)[:10]

print(f'\nPackages with GitHub info: {len(package_stars)}')
print('\nTop packages by GitHub stars:')
for pkg in top_packages:
    print(f"{pkg['name']}@{pkg['version']} - {pkg['project_name']} - {pkg['stars']} stars")

print('__RESULT__:')
print(json.dumps({
    'packages_with_stars': len(package_stars),
    'top_packages': top_packages[:5]
}))"}

